 {"id":"bd-131","title":"Implement DDL generation from schema operations","description":"# Task: Implement DDL Generation from Schema Operations

## Context
DDL (Data Definition Language) generation takes SchemaOp operations from the diff engine and produces executable SQL statements for each supported database (SQLite, MySQL, PostgreSQL).

## Design Principles
1. **Database-specific**: Different dialects for each DB
2. **Ordered execution**: Generated DDL respects FK dependencies
3. **Transactional**: Wrap in transaction where supported
4. **Reversible**: Generate rollback DDL alongside forward DDL

## What to Implement

### 1. DDL Generator Trait
\`\`\`rust
/// Generates DDL SQL from schema operations.
pub trait DdlGenerator {
    /// The database dialect name.
    fn dialect(&self) -> &'static str;

    /// Generate DDL for a schema operation.
    fn generate(&self, op: &SchemaOp) -> Vec<String>;

    /// Generate DDL for multiple operations.
    fn generate_all(&self, ops: &[SchemaOp]) -> Vec<String> {
        ops.iter().flat_map(|op| self.generate(op)).collect()
    }

    /// Generate rollback DDL (inverse operations).
    fn generate_rollback(&self, ops: &[SchemaOp]) -> Vec<String> {
        ops.iter()
            .rev()
            .filter_map(|op| op.inverse())
            .flat_map(|op| self.generate(&op))
            .collect()
    }
}
\`\`\`

### 2. SQLite Generator
\`\`\`rust
pub struct SqliteDdlGenerator;

impl DdlGenerator for SqliteDdlGenerator {
    fn dialect(&self) -> &'static str { "sqlite" }

    fn generate(&self, op: &SchemaOp) -> Vec<String> {
        match op {
            SchemaOp::CreateTable(table) => {
                vec![self.create_table_sql(table)]
            }
            SchemaOp::DropTable { name, cascade } => {
                vec![format!("DROP TABLE IF EXISTS {}", name)]
            }
            SchemaOp::AddColumn { table, column } => {
                vec![format!("ALTER TABLE {} ADD COLUMN {}",
                    table,
                    self.column_def(column)
                )]
            }
            SchemaOp::DropColumn { table, column } => {
                // SQLite doesn't support DROP COLUMN directly
                // Must recreate table
                self.recreate_table_without_column(table, column)
            }
            SchemaOp::CreateIndex { table, index } => {
                let unique = if index.unique { "UNIQUE " } else { "" };
                vec![format!("CREATE {}INDEX {} ON {} ({})",
                    unique,
                    index.name,
                    table,
                    index.columns.join(", ")
                )]
            }
            // ... other operations
        }
    }

    fn create_table_sql(&self, table: &TableSchema) -> String {
        let mut sql = format!("CREATE TABLE IF NOT EXISTS {} (\n", table.name);

        let column_defs: Vec<String> = table.columns.iter()
            .map(|c| format!("  {}", self.column_def(c)))
            .collect();

        sql.push_str(&column_defs.join(",\n"));

        // Primary key constraint
        if !table.primary_key.is_empty() {
            sql.push_str(&format!(",\n  PRIMARY KEY ({})", table.primary_key.join(", ")));
        }

        // Foreign key constraints
        for fk in &table.foreign_keys {
            sql.push_str(&format!(",\n  FOREIGN KEY ({}) REFERENCES {}({}) ON DELETE {} ON UPDATE {}",
                fk.columns.join(", "),
                fk.referenced_table,
                fk.referenced_columns.join(", "),
                fk.on_delete.as_sql(),
                fk.on_update.as_sql()
            ));
        }

        sql.push_str("\n)");
        sql
    }

    fn column_def(&self, col: &ColumnSchema) -> String {
        let mut def = format!("{} {}", col.name, col.sql_type);

        if !col.nullable {
            def.push_str(" NOT NULL");
        }

        if let Some(default) = &col.default {
            def.push_str(&format!(" DEFAULT {}", default));
        }

        if col.is_auto_increment {
            // SQLite uses INTEGER PRIMARY KEY for auto-increment
            // This is handled in PRIMARY KEY constraint
        }

        def
    }
}
