fn generate_relationships_const(model: &ModelDef) -> proc_macro2::TokenStream {
    let relationship_fields: Vec<_> = model.fields.iter()
        .filter(|f| f.relationship.is_some())
        .collect();

    if relationship_fields.is_empty() {
        return quote::quote! {
            const RELATIONSHIPS: &'static [sqlmodel_core::RelationshipInfo] = &[];
        };
    }

    let infos: Vec<_> = relationship_fields.iter().map(|f| {
        let rel = f.relationship.as_ref().unwrap();
        let field_name = &f.name;
        let related_table = &rel.model; // Will need runtime resolution
        let kind = /* determine from field type */;

        let local_key = if let Some(fk) = &rel.foreign_key {
            quote::quote! { .local_key(#fk) }
        } else {
            quote::quote! {}
        };

        let remote_key = if let Some(rk) = &rel.remote_key {
            quote::quote! { .remote_key(#rk) }
        } else {
            quote::quote! {}
        };

        let back_pop = if let Some(bp) = &rel.back_populates {
            quote::quote! { .back_populates(#bp) }
        } else {
            quote::quote! {}
        };

        quote::quote! {
            sqlmodel_core::RelationshipInfo::new(
                stringify!(#field_name),
                #related_table, // Table name of related model
                sqlmodel_core::RelationshipKind::#kind
            )
            #local_key
            #remote_key
            #back_pop
            .lazy(#lazy)
            .cascade_delete(#cascade)
        }
    }).collect();

    quote::quote! {
        const RELATIONSHIPS: &'static [sqlmodel_core::RelationshipInfo] = &[
            #(#infos),*
        ];
    }
}
