/// E2E: Full migration workflow
#[tokio::test]
async fn e2e_migration_workflow() {
    let pool = setup_test_pool().await;
    let temp_dir = tempfile::tempdir().unwrap();

    // 1. Compute schema diff
    let introspector = SchemaIntrospector::new(&pool);
    let current = introspector.introspect().await.unwrap();
    let desired = SchemaExtractor::extract::<(Hero, Team)>();

    let differ = SchemaDiffer::default();
    let diff = differ.diff(&current, &desired);

    tracing::info!(ops = diff.ops.len(), "Schema diff computed");

    // 2. Generate migration
    let ddl = SqliteDdlGenerator;
    let migration = Migration::from_diff(&diff, &ddl, "Create heroes and teams tables");

    tracing::info!(
        version = %migration.version,
        up_count = migration.up.len(),
        down_count = migration.down.len(),
        "Migration generated"
    );

    // 3. Write migration file
    let writer = MigrationWriter::new(temp_dir.path().join("migrations"));
    let path = writer.write(&migration).unwrap();

    tracing::info!(path = %path.display(), "Migration written");

    // 4. Apply migration
    let mut conn = pool.acquire().await.unwrap();
    let mut runner = MigrationRunner::new(&mut conn);
    runner.ensure_schema().await.unwrap();

    let result = runner.migrate(&[migration.clone()]).await.unwrap();
    assert_eq!(result.applied, 1);

    tracing::info!(applied = result.applied, "Migration applied");

    // 5. Verify schema created
    let new_schema = introspector.introspect().await.unwrap();
    assert!(new_schema.iter().any(|t| t.name == "heroes"));
    assert!(new_schema.iter().any(|t| t.name == "teams"));

    // 6. Rollback
    runner.rollback(&migration).await.unwrap();

    // 7. Verify rollback
    let rolled_back = introspector.introspect().await.unwrap();
    assert!(!rolled_back.iter().any(|t| t.name == "heroes"));

    tracing::info!("Migration rollback successful");
}

